<template>
  <div style="background-color: #002366;">
    <scrollactive
      scrollContainerSelector=".router-view"
      :offset="0"
      :always-track="true"
      bezier-easing-value=".5,0,.35,1"
      class="py-2"
      style="display: flex; justify-content: space-evenly; max-width: 38.0rem; margin: 0 auto;"
      @itemchanged="scrollactiveChanged">
      <a href="mailto:lovohh@gmail.com">
        <named-icon
          :color="getColor(0)"
          icon="envelope"
          name="Contact"
        />
      </a>
      <a href="/doc/lovohh_resume.pdf" download>
        <named-icon
          :color="getColor(1)"
          icon="file"
          name="Resume"
        />
      </a>
      <a href="#landing" class="scrollactive-item" :val="2">
        <named-icon
          :color="getColor(2)"
          icon="home"
          name="Home"
        />
      </a>
      <a href="#about" class="scrollactive-item" :val="3">
        <named-icon
          :color="getColor(3)"
          icon="user"
          name="About"
        />
      </a>
      <a href="#experience" class="scrollactive-item" :val="4">
        <named-icon
          :color="getColor(4)"
          icon="book"
          name="Experience"
        />
      </a>
    </scrollactive>
  </div>
</template>

<script>
import { mapGetters, mapMutations } from 'vuex';

export default {
  name: 'MainNavigationBar',

  components: {
    NamedIcon: () => import('@/components-ui/NamedIcon.vue'),
  },

  computed: {
    ...mapGetters('bottomNavigationBar', ['current']),
  },

  methods: {
    ...mapMutations('bottomNavigationBar', ['setCurrent']),

    scrollactiveChanged: function (event, currentEle) {
      const n = parseInt(currentEle.getAttribute('val'), 10);
      this.setCurrent(n);
    },

    isActive: function (n) {
      return this.current === n;
    },

    getColor: function (n) {
      return this.isActive(n) ? '#ffff' : '#fff6';
    },
  },
};
</script>

